import React, { useState } from "react";
import {
  Button,
  TextField,
  Typography,
  Alert,
  CircularProgress,
  Paper,
  Container,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { sendOtp, verifyOtp } from "../services/api";

export default function UserLogin() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [loading, setLoading] = useState(false);
  const [otpSent, setOtpSent] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  const handleSendOtp = async () => {
    if (!/^[6-9]\d{9}$/.test(mobile)) {
      setError("Enter a valid 10-digit mobile number.");
      return;
    }
    setLoading(true);
    setError("");
    setSuccess("");
    try {
      const res = await sendOtp(mobile, "user");
      if (res.data?.success) {
        setOtpSent(true);
        setSuccess("OTP sent successfully!");
      } else {
        setError(res.data?.message || "Failed to send OTP");
      }
    } catch {
      setError("Server error. Try again later.");
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async () => {
    if (otp.length !== 6) {
      setError("Enter a valid 6-digit OTP.");
      return;
    }
    setLoading(true);
    setError("");
    setSuccess("");
    try {
      const res = await verifyOtp(mobile, otp, "user");
      if (res.data?.success) {
        const { token, role } = res.data.data;
        localStorage.setItem("token", token);
        localStorage.setItem("role", role);
        navigate("/user-dashboard");
      } else {
        setError("OTP verification failed.");
      }
    } catch {
      setError("Server error. Try again later.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container
      maxWidth="sm"
      sx={{ display: "flex", justifyContent: "center", alignItems: "center", height: "100vh" }}
    >
      <Paper sx={{ p: 5, borderRadius: 4, boxShadow: 5, width: "100%", textAlign: "center" }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 1, color: "primary.main" }}>
          User Login
        </Typography>
        <Typography variant="body2" sx={{ mb: 3, color: "text.secondary" }}>
          Sign in securely with your mobile number
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <TextField
          fullWidth
          label="Mobile Number"
          value={mobile}
          onChange={(e) => setMobile(e.target.value)}
          margin="normal"
          disabled={otpSent}
        />

        {otpSent && (
          <TextField
            fullWidth
            label="Enter OTP"
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            margin="normal"
          />
        )}

        {!otpSent ? (
          <Button fullWidth sx={{ mt: 2, py: 1.3 }} variant="contained" onClick={handleSendOtp} disabled={loading}>
            {loading ? <CircularProgress size={24} /> : "Send OTP"}
          </Button>
        ) : (
          <Button fullWidth sx={{ mt: 2, py: 1.3 }} variant="contained" onClick={handleVerifyOtp} disabled={loading}>
            {loading ? <CircularProgress size={24} /> : "Verify OTP"}
          </Button>
        )}

        <Typography sx={{ mt: 3 }}>
          Don’t have an account?{" "}
          <Button variant="text" onClick={() => navigate("/register")} sx={{ fontWeight: "bold" }}>
            Signup
          </Button>
        </Typography>
        <Typography sx={{ mt: 1 }}>
          Are you a Rider?{" "}
          <Button variant="text" onClick={() => navigate("/rider-login")} sx={{ fontWeight: "bold" }}>
            Login as Rider
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
